namespace BgCommon;/// <summary>/// 平台工具类，用于获取和判断操作系统及架构信息./// </summary>public static class PlatformUtil{    /// <summary>    /// 受支持的处理器架构列表.    /// </summary>    private static readonly IReadOnlyList<Architecture> SupportedArchitectures =    [        Architecture.X64,        Architecture.X86,        Architecture.Arm64    ];    /// <summary>    /// 获取当前操作系统平台.    /// </summary>    /// <returns> 返回当前的 <see cref="OSPlatform"/>. </returns>    /// <exception cref="Exception"> 当无法识别当前操作系统时抛出异常. </exception>    public static OSPlatform GetOSPlatform()    {        // 检查是否为 Windows 平台.        if (RuntimeInformation.IsOSPlatform(OSPlatform.Windows))        {            return OSPlatform.Windows;        }        // 检查是否为 OSX 平台.        if (RuntimeInformation.IsOSPlatform(OSPlatform.OSX))        {            return OSPlatform.OSX;        }        // 检查是否为 Linux 平台.        if (RuntimeInformation.IsOSPlatform(OSPlatform.Linux))        {            return OSPlatform.Linux;        }        // 检查是否为 FreeBSD 平台.        if (RuntimeInformation.IsOSPlatform(OSPlatform.FreeBSD))        {            return OSPlatform.FreeBSD;        }        // 如果所有已知平台都不匹配，则抛出异常.        throw new NotSupportedException($"Could not determine OS platform. OS: {RuntimeInformation.OSDescription}");    }    /// <summary>    /// 获取一个值，该值指示当前操作系统是否为 Windows.    /// </summary>    /// <returns> 如果是 Windows 则返回 true，否则返回 false. </returns>    public static bool IsOSWindows() => RuntimeInformation.IsOSPlatform(OSPlatform.Windows);    /// <summary>    /// 获取一个值，该值指示当前操作系统是否为 OSX.    /// </summary>    /// <returns> 如果是 OSX 则返回 true，否则返回 false. </returns>    public static bool IsOSMacOs() => RuntimeInformation.IsOSPlatform(OSPlatform.OSX);    /// <summary>    /// 获取一个值，该值指示当前操作系统是否为 Linux 或 FreeBSD.    /// </summary>    /// <returns> 如果是 Linux 或 FreeBSD 则返回 true，否则返回 false. </returns>    public static bool IsOSLinuxOrFreeBsd() => RuntimeInformation.IsOSPlatform(OSPlatform.Linux) ||                                               RuntimeInformation.IsOSPlatform(OSPlatform.FreeBSD);    /// <summary>    /// 获取一个值，该值指示当前操作系统架构是否受支持.    /// </summary>    /// <param name="throwIfNotSupported"> 如果不支持是否抛出异常. </param>    /// <returns> 如果架构受支持则返回 true，否则返回 false. </returns>    /// <exception cref="PlatformNotSupportedException"> 当架构不支持且 throwIfNotSupported 为 true 时抛出. </exception>    public static bool IsOsArchitectureSupported(bool throwIfNotSupported = false)    {        // 判断当前架构是否存在于受支持列表中.        bool isCurrentArchitectureSupported = SupportedArchitectures.Contains(RuntimeInformation.OSArchitecture);        // 如果不支持且要求抛出异常，则执行抛出逻辑.        if (!isCurrentArchitectureSupported && throwIfNotSupported)        {            throw new PlatformNotSupportedException(                $"OS Architecture '{RuntimeInformation.OSArchitecture}' is not supported. OS: ({RuntimeInformation.OSDescription})");        }        return isCurrentArchitectureSupported;    }    /// <summary>    /// 获取平台可执行文件的后缀名.    /// </summary>    /// <returns> Windows 平台返回 ".exe"，其他平台返回空字符串. </returns>    public static string GetPlatformExecutableExtension() => IsOSWindows() ? ".exe" : string.Empty;}